const form=document.querySelector("#form");const id=document.querySelector("#id");const titulo=document.querySelector("#titulo");const conteudo=document.querySelector("#conteudo");form.addEventListener("submit",(e)=>{e.preventDefault();if(id){const valId=converterNum(id.value);if(!validarId(valId)){alternarDialogo(!0,"O ID é obrigatório e deve ser um número inteiro maior ou igual a 1. Por favor, tente novamente.");limparCampo(id);return}}
const valTitulo=limparVal(titulo.value);const valConteudo=limparVal(conteudo.value);if(!validarCampoObrigatorio(titulo,valTitulo,80)){alternarDialogo(!0,"O título é obrigatório e deve ter no máximo 80 caracteres. Por favor, tente novamente.");limparCampo(titulo);return}
if(!validarCampoObrigatorio(conteudo,valConteudo,200)){alternarDialogo(!0,"O conteúdo é obrigatório e deve ter no máximo 200 caracteres. Por favor, tente novamente.");limparCampo(conteudo);return}
e.currentTarget.submit()})